98	  let quoteIndex = 0;
99	  const results = scenario.steps.map((step: any, index: number) => {
100	    if (step.op === "claim") {
101	      const policy = policies[step.policy];
102	      const insuranceSum = policy.items.reduce(
103	        (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0),
104	        0,
105	      );
106	      const cap = insuranceSum * 2;
107	      const totalPayout = step.incident.damages.reduce(
108	        (sum: number, d: any) => sum + Math.max(0, d.amount - DEDUCTIBLE),
109	        0,
110	      );
111	      const payout = Math.min(totalPayout, cap);
112	      return { payout, remainingCap: cap - payout };
113	    }
114	    const premium = calculateQuotePremium(step, scenario.customer, quoteIndex);
115	    policies[index] = step;
116	    quoteIndex++;
117	    return { premium };
118	  });
119	  return { results };
120	};
