16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const MAIN_ITEM_TYPES = ["sword", "amulet", "staff", "potion"];
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	
26	const isMainItem = (item: any): boolean =>
27	  MAIN_ITEM_TYPES.includes(item.type);
28	
29	const premiumForType = (type: string): number =>
30	  BASE_PREMIUMS[type] ?? 0;
31	
32	const countByType = (items: any[]): Record<string, number> => {
33	  const counts: Record<string, number> = {};
34	  for (const item of items) {
35	    counts[item.type] = (counts[item.type] ?? 0) + 1;
36	  }
37	  return counts;
38	};
39	
40	const calculateComponentPremium = (components: any[]): number => {
41	  const countsByType = countByType(components);
42	  return Object.entries(countsByType).reduce(
43	    (total, [type, count]) =>
44	      total +
45	      (count === COMPONENT_BLOCK_SIZE
46	        ? COMPONENT_BLOCK_PREMIUM
47	        : count * premiumForType(type)),
48	    0,
49	  );
50	};
51	
52	const calculateItemSurcharges = (item: any): number => {
53	  const base = premiumForType(item.type);
54	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
55	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
56	  return cursedSurcharge + enchantmentSurcharge;
57	};
58	
59	const calculateQuotePremium = (
60	  step: any,
61	  customer: any,
62	  quoteIndex: number,
63	): number => {
64	  const mainItems = step.items.filter(isMainItem);
65	  const components = step.items.filter((item: any) => !isMainItem(item));
66	
67	  const mainBasePremium = mainItems.reduce(
68	    (sum: number, item: any) => sum + premiumForType(item.type),
69	    0,
70	  );
71	
72	  const itemSurcharges = mainItems.reduce(
73	    (sum: number, item: any) => sum + calculateItemSurcharges(item),
74	    0,
75	  );
76	
77	  const componentTotal = calculateComponentPremium(components);
78	  const policyBasePremium = mainBasePremium + componentTotal;
79	
80	  const firstInsurance = policyBasePremium * 0.1;
81	  const loyaltyDiscount =
82	    customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
83	  const followUpDiscount =
84	    quoteIndex > 0 ? policyBasePremium * 0.15 : 0;
85	
86	  return Math.ceil(
87	    policyBasePremium +
88	      itemSurcharges +
89	      firstInsurance -
90	      loyaltyDiscount -
91	      followUpDiscount +
92	      PROCESSING_FEE,
93	  );
94	};
95	
96	const calculateClaimResult = (step: any, policy: any): any => {
97	  const insuranceSum = policy.items.reduce(
98	    (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0),
99	    0,
100	  );
101	  const cap = insuranceSum * 2;
102	  const totalPayout = step.incident.damages.reduce(
103	    (sum: number, d: any) => sum + Math.max(0, d.amount - DEDUCTIBLE),
104	    0,
105	  );
106	  const payout = Math.min(totalPayout, cap);
107	  return { payout, remainingCap: cap - payout };
108	};
109	
110	export const processScenario = (scenario: any): any => {
111	  const policies: any[] = [];
112	  let quoteIndex = 0;
113	  const results = scenario.steps.map((step: any, index: number) => {
114	    if (step.op === "claim") {
115	      return calculateClaimResult(step, policies[step.policy]);
116	    }
117	    const premium = calculateQuotePremium(step, scenario.customer, quoteIndex);
118	    policies[index] = step;
119	    quoteIndex++;
120	    return { premium };
121	  });
122	  return { results };
123	};
